  clientMessageId: string;
  workspaceId: string;
  conversationId?: string;
  text: string;
  onboardingAction?: OnboardingAction;
  discussEntityId?: string;  // <-- Passed to chat system
};
```

**Step 7: Chat Session Cleanup** (`app/src/client/hooks/use-chat-session.ts`, lines 453-455):
```typescript
if (isNewConversation) {
  setActiveConversationId(payload.conversationId);
  if (discussEntity) {
    clearDiscussEntity();  // Clear after sending first message
  }
}
```

---

## 7. Action Execution (Non-"discuss" Actions)

**File: `/Users/marcus/conductor/workspaces/brain/montevideo-v1/app/src/server/entities/entity-actions-route.ts`**

The action endpoint processes:

```typescript
POST /api/entities/{entityId}/actions?workspaceId={workspaceId}
Body: { action: string, notes?: string, newSummary?: string, priority?: string }
```

**Supported actions by table:**

- **Decision table:**
  - `confirm`: Calls `confirmDecisionRecord()`, triggers description updates, sets status to "confirmed"
  - `override`: Updates summary, sets status to "overridden", stores override_notes
  - (NOT `complete` or `acknowledge`)

- **Question table:**
  - `set_priority`: Updates priority field
  - (NOT `confirm`, `override`, `complete`, `acknowledge`, `resolve`)

- **Task table:**
  - `complete`: Sets status to "done", sets completed_at and updated_at timestamps
  - `set_priority`: Updates priority field
  - (NOT `confirm`, `override`, `acknowledge`, `resolve`)

- **Observation table** (special handling, lines 66-90):
  - `acknowledge`: Calls `acknowledgeObservation()`
  - `resolve`: Calls `resolveObservation()`
  - (Different from other entity types)

**Note:** The action endpoint validates that the action is supported for the entity type and returns 400 if mismatched.

---

## 8. Questions - Current Capabilities vs Actions

**Where Questions Appear:**
- **Blocking tier only** - High/critical priority open questions (lines 127-144 in feed-route.ts)
- Uses `listBlockingQuestions()` query from feed-queries.ts

**Available Actions for Questions:**
```typescript
function questionActions(): GovernanceFeedAction[] {
  return [
    { action: "resolve", label: "Resolve" },
    { action: "discuss", label: "Discuss" },
  ];
}
```

**Question Query Details** (lines 208-276 in feed-queries.ts):
```typescript
export async function listBlockingQuestions(
  input: WorkspaceQueryInput,
): Promise<BlockingQuestionRow[]> {
  // Selects: id, text, status, priority, category, created_at
  // WHERE status = 'open'
  // AND priority IN ['high', 'critical']
  // AND workspace = $workspace
  // ORDER BY created_at DESC
}
```

**Important:** The action handler (`entity-actions-route.ts`) does NOT currently support `resolve` action for questions (line 37 lists allowed actions, and question handling is not in the switch statements). This means **the "resolve" button on questions likely doesn't work** - it would return a 400 error from the action endpoint.

---

## Summary of Action Support

| Entity Type | Actions in Feed | Server Support | Notes |
|-------------|-----------------|-----------------|-------|
| **Decision** | confirm, override, discuss | confirm, override | Both work |
| **Question** | resolve, discuss | (none explicitly) | resolve button won't work; discuss works |
| **Conflict** | acknowledge, resolve, discuss | (none explicitly) | Only discuss works; acknowledge/resolve not handled |
| **Observation** | acknowledge/resolve (based on status), (no discuss) | acknowledge, resolve | Full support |
| **Blocked Task** | complete, discuss | complete | Both work |
| **Stale Task** | complete, discuss | complete | Both work |
| **Completed Items** | (none) | N/A | No actions |
| **Extractions** | (none) | N/A | No actions |

