        id: `extraction:${row.edgeId}`,
        tier: "awareness",
        entityId,
        entityKind: row.entityKind as EntityKind,
        entityName: row.entityName,
        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
        status: "extracted",
        createdAt: row.extractedAt,
        actions: [],
      });
    }

